mapper.select:
SELECT , COALESCE(fs.management_area, 0) AS management_area, COALESCE(rs.rentable_area, 0) AS rentable_area, COALESCE(rs.total_room_count, 0) AS total_room_count, COALESCE(rs.rentable_room_count, 0) AS rentable_room_count FROM ics_park p LEFT JOIN ( SELECT park_id, SUM(COALESCE(area, 0)) AS management_area FROM ics_floor GROUP BY park_id ) fs ON fs.park_id = p.id LEFT JOIN ( SELECT park_id, COUNT(1) AS total_room_count, SUM(CASE WHEN status = '0' THEN 1 ELSE 0 END) AS rentable_room_count, SUM(CASE WHEN status = '0' THEN COALESCE(area, 0) ELSE 0 END) AS rentable_area FROM ics_room GROUP BY park_id ) rs ON rs.park_id = p.id
AND p.id = #{park.id} AND p.name LIKE CONCAT('%', #{park.name}, '%') AND p.code LIKE CONCAT('%', #{park.code}, '%') AND p.status = #{park.status}
ORDER BY p.id DESC
